// HasOrder applies the HasEdge predicate on the "order" edge.
func HasOrder() predicate.POSOrderLine {
	return predicate.POSOrderLine(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, OrderTable, OrderColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasOrderWith applies the HasEdge predicate on the "order" edge with a given conditions (other predicates).
func HasOrderWith(preds ...predicate.POSOrder) predicate.POSOrderLine {
	return predicate.POSOrderLine(func(s *sql.Selector) {
		step := newOrderStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// HasModifiers applies the HasEdge predicate on the "modifiers" edge.
func HasModifiers() predicate.POSOrderLine {
	return predicate.POSOrderLine(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, ModifiersTable, ModifiersColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasModifiersWith applies the HasEdge predicate on the "modifiers" edge with a given conditions (other predicates).
func HasModifiersWith(preds ...predicate.POSLineModifier) predicate.POSOrderLine {
	return predicate.POSOrderLine(func(s *sql.Selector) {
		step := newModifiersStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.POSOrderLine) predicate.POSOrderLine {
	return predicate.POSOrderLine(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.POSOrderLine) predicate.POSOrderLine {
	return predicate.POSOrderLine(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.POSOrderLine) predicate.POSOrderLine {
	return predicate.POSOrderLine(sql.NotPredicates(p))
}
